  @Override
  public Track getHarmony() {
    Track t = new Track().withDefaults(HARMONY_VOL, HARMONY_DUTY).withDecay(SOSTENUTO);
    p2Bar00(t);
    p2Bar01(t);
    p2Bar02(t);
    p2Bar03(t);
    p2Bar04(t);
    p2Bar05(t);
    p2Bar06(t);
    p2Bar07(t);
    p2Bar08(t);
    p2Bar09(t);
    p2Bar10(t);
    p2Bar11(t);
    p2Bar12(t);
    p2Bar13(t);
    p2Bar14(t);
    p2Bar15(t);
    p2Bar16(t);
    p2Bar17(t);
    p2Bar18(t);
    p2Bar19(t);
    p2Bar20(t);
    p2Bar21(t);
    p2Bar22(t);
    p2Bar23(t);
    // hand-tune: the captured harmony sits ~half the lead's level; lift it so
    // the inner voice reads through the mix. 1.15 = halfway between the raw
    // level (too quiet) and 1.3 (too loud).
    return t.scaleVolume(1.15);
  }

